  2→import React, { useState, useEffect } from 'react';
  3→import { createPortal } from 'react-dom';
  4→import { GeneratedSolution } from '../types';
  5→import { X, Copy, Check, Sparkles, Loader2, ClipboardList, Briefcase, ArrowRight, UserCheck, Download, FileCode } from 'lucide-react';
  6→
  7→interface Props {
  8→  isOpen: boolean;
  9→  onClose: () => void;
 10→  solution: GeneratedSolution | null;
 11→  isLoading: boolean;
 12→}
 13→
 14→const GenerationModal: React.FC<Props> = ({ isOpen, onClose, solution, isLoading }) => {
 15→  const [copied, setCopied] = useState(false);
 16→
 17→  useEffect(() => {
 18→    if (isOpen) {
 19→      document.body.style.overflow = 'hidden';
 20→    }
 21→    return () => { document.body.style.overflow = ''; };
 22→  }, [isOpen]);
 23→
 24→  if (!isOpen) return null;
 25→
 26→  const handleCopy = () => {
 27→    if (solution?.content) {
 28→      navigator.clipboard.writeText(solution.content);
 29→      setCopied(true);
 30→      setTimeout(() => setCopied(false), 2000);
 31→    }
 32→  };
 33→
 34→  const handleDownload = () => {
 35→    if (solution?.content) {
 36→        const extension = solution.language === 'html' ? 'html' : solution.language === 'json' ? 'json' : 'txt';
 37→        const blob = new Blob([solution.content], { type: 'text/plain' });
 38→        const url = URL.createObjectURL(blob);
 39→        const a = document.createElement('a');
 40→        a.href = url;
 41→        a.download = `solution_aeo.${extension}`;
 42→        document.body.appendChild(a);
 43→        a.click();
 44→        document.body.removeChild(a);
 45→        URL.revokeObjectURL(url);
 46→    }
 47→  };
 48→
 49→  const handleContactExpert = () => {
 50→    // In a real app, this would open a booking calendar or contact form
 51→    window.open('mailto:experts@citedby.ai?subject=Demande%20assistance%20Webmaster%20AEO', '_blank');
 52→  };
 53→
 54→  const modalContent = (
 55→    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
 56→      {/* Backdrop */}
 57→      <div
 58→        className="absolute inset-0 bg-black/80 backdrop-blur-sm transition-opacity"
 59→        onClick={onClose}
 60→      ></div>
 61→
 62→      {/* Modal Content */}
 63→      <div className="relative bg-[#0f1115] border border-white/[0.08] rounded-2xl w-full max-w-5xl h-[80vh] flex flex-col shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-200">
 64→
 65→        {/* Header */}
 66→        <div className="shrink-0 px-6 py-4 border-b border-white/[0.08] flex items-center justify-between bg-white/[0.04]">
 67→          <div className="flex items-center gap-3">
 68→            <div className="w-10 h-10 rounded-2xl bg-gradient-to-br from-primary/20 to-secondary/20 flex items-center justify-center text-purple-400 border border-white/[0.06] shadow-inner">
 69→              <Sparkles size={20} />
 70→            </div>
 71→            <div>
 72→              <h3 className="text-lg font-sans font-bold text-white">
 73→                {isLoading ? 'Génération de la solution...' : solution?.title}
 74→              </h3>
 75→              {!isLoading && <p className="text-xs text-gray-500">Optimisation AEO générée par l'IA</p>}
 76→            </div>
 77→          </div>
 78→          <button
 79→            onClick={onClose}
 80→            className="p-2 hover:bg-white/[0.08] rounded-full transition-colors text-gray-500 hover:text-white"
 81→          >
 82→            <X size={20} />
 83→          </button>
 84→        </div>
 85→
 86→        {/* Body */}
 87→        <div className="flex-1 min-h-0 overflow-hidden bg-[#000000]">
 88→          {isLoading ? (
 89→            <div className="flex flex-col items-center justify-center h-full py-20 text-center space-y-6">
 90→              <div className="relative">
 91→                <Loader2 size={64} className="text-purple-400 animate-spin" />
 92→                <div className="absolute inset-0 blur-xl bg-purple-500/20 rounded-full animate-pulse"></div>
 93→              </div>
 94→              <div className="space-y-2">
 95→                <p className="text-white font-medium text-lg animate-pulse">
 96→                  Analyse des critères de citation en cours...
 97→                </p>
 98→                <p className="text-sm text-gray-500">
 99→                  Rédaction du code et du guide d'implémentation pour débutant
100→                </p>
101→              </div>
102→            </div>
103→          ) : solution ? (
104→            <div className="grid lg:grid-cols-12 h-full">
105→
106→              {/* Left Column: The Code/Content (7 cols) */}
107→              <div className="lg:col-span-7 p-6 border-b lg:border-b-0 lg:border-r border-white/[0.08] flex flex-col min-h-0 overflow-y-auto custom-scrollbar">
108→                <div className="bg-blue-500/10 border border-blue-500/20 p-4 rounded-2xl text-sm text-blue-200 mb-6 leading-relaxed shrink-0">
109→                  <span className="font-bold text-blue-300 block mb-1">Impact AEO :</span>
110→                  {solution.explanation}
111→                </div>
112→
113→                <div className="flex-1 flex flex-col min-h-0">
114→                  <div className="flex justify-between items-center mb-3 shrink-0">
115→                    <span className="text-xs font-bold text-gray-500 uppercase tracking-wider flex items-center gap-2">
116→                      <FileCode size={14} className="text-gray-500" />
117→                      {solution.type === 'code' ? 'Fichiers Sources' : 'Contenu Optimisé'}
118→                      <span className="text-[10px] bg-white/[0.08] px-1.5 py-0.5 rounded text-gray-500 font-normal normal-case">{solution.language}</span>
119→                    </span>
120→                    <div className="flex gap-2">
121→                        <button
122→                        onClick={handleDownload}
123→                        className="flex items-center gap-2 px-3 py-1.5 bg-white/[0.04] hover:bg-purple-500/10 rounded-md text-xs font-medium text-white transition-all border border-white/[0.08] group"
124→                        title="Télécharger le fichier"
125→                        >
126→                        <Download size={14} className="group-hover:text-purple-400 transition-colors" />
127→                        Télécharger
128→                        </button>
129→                        <button
130→                        onClick={handleCopy}
131→                        className="flex items-center gap-2 px-3 py-1.5 bg-white/[0.04] hover:bg-purple-500/10 rounded-md text-xs font-medium text-white transition-all border border-white/[0.08] group"
132→                        >
133→                        {copied ? <Check size={14} className="text-purple-300" /> : <Copy size={14} className="group-hover:text-purple-400 transition-colors" />}
134→                        {copied ? 'Copié !' : 'Copier'}
135→                        </button>
136→                    </div>
137→                  </div>
138→
139→                  <div className="relative flex-1 min-h-[200px] bg-[#111111] rounded-2xl border border-white/[0.08] overflow-hidden shadow-inner group">
140→                    <pre className="absolute inset-0 p-5 overflow-auto text-sm font-mono leading-relaxed text-gray-300 custom-scrollbar">
141→                      <code>{solution.content}</code>
142→                    </pre>
143→                  </div>
144→                </div>
145→              </div>
146→
147→              {/* Right Column: Implementation Plan (5 cols) */}
148→              <div className="lg:col-span-5 bg-purple-500/[0.02] flex flex-col min-h-0 border-l border-black">
149→                <div className="flex-1 min-h-0 overflow-y-auto custom-scrollbar p-6 pb-2">
150→                    <h4 className="text-lg font-sans font-bold mb-6 flex items-center gap-2 text-white">
151→                    <ClipboardList size={20} className="text-purple-400" />
152→                    Guide d'installation (Débutant)
153→                    </h4>
154→
155→                    <div className="space-y-0">
156→                    {solution.implementationSteps.map((step, idx) => (
157→                        <div key={idx} className="flex gap-4 pb-6 last:pb-0 relative group">
158→                            {/* Vertical Line */}
159→                            {idx !== solution.implementationSteps.length - 1 && (
160→                                <div className="absolute left-[11px] top-8 bottom-0 w-px bg-white/[0.08] group-hover:bg-white/20 transition-colors"></div>
161→                            )}
162→
163→                            <div className="w-6 h-6 rounded-full bg-[#1a1d24] border border-white/20 flex items-center justify-center text-xs font-bold shrink-0 mt-0.5 z-10 text-gray-500 group-hover:text-purple-400 group-hover:border-primary/50 transition-colors shadow-lg">
164→                                {idx + 1}
165→                            </div>
166→                            <p className="text-sm text-gray-300 leading-relaxed pt-0.5 group-hover:text-gray-100 transition-colors">{step}</p>
167→                        </div>
168→                    ))}
169→                    </div>
170→                </div>
171→
172→                <div className="shrink-0 px-6 py-4 border-t border-white/[0.08]">
173→                   <div className="bg-gradient-to-br from-purple-500/5 to-purple-500/[0.02] p-5 rounded-2xl border border-white/[0.08] hover:border-primary/30 transition-all group">
174→                        <div className="flex items-center gap-3 mb-3">
175→                            <div className="w-8 h-8 rounded-full bg-accent/20 flex items-center justify-center text-accent">
176→                                <Briefcase size={16} />
177→                            </div>
178→                            <h5 className="font-bold text-white text-sm">Déléguer cette tâche ?</h5>
179→                        </div>
180→                        <p className="text-xs text-gray-500 mb-4 leading-relaxed">
181→                            Envoyez ce guide et les fichiers à votre webmaster ou demandez l'assistance d'un expert certifié AEO.
182→                        </p>
183→                        <button
184→                            onClick={handleContactExpert}
185→                            className="w-full py-2.5 bg-gradient-to-r from-purple-500 to-violet-600 text-white hover:from-purple-400 hover:to-violet-500 font-bold rounded-full transition-colors flex items-center justify-center gap-2 text-xs uppercase tracking-wide shadow-lg transform active:scale-95"
186→                        >
187→                            <UserCheck size={14} />
188→                            Trouver un Webmaster
189→                        </button>
190→                   </div>
191→                </div>
192→              </div>
193→
194→            </div>
195→          ) : null}
196→        </div>
197→      </div>
198→    </div>
199→  );
200→
201→  return createPortal(modalContent, document.body);
202→};
203→
204→export default GenerationModal;
