  1→import React, { useState, useEffect } from 'react';
  2→import { Project, SourceOfTruthData } from '../types';
  3→import { LLM_TRUTH_TEMPLATES } from '../services/llm_templates';
  4→import { X, FileText, Download, Copy, Sparkles, Check, Plus, Trash2, Building2, MapPin, Calendar } from 'lucide-react';
  5→
  6→interface Props {
  7→  isOpen: boolean;
  8→  onClose: () => void;
  9→  project: Project | null;
 10→}
 11→
 12→const SourceOfTruthModal: React.FC<Props> = ({ isOpen, onClose, project }) => {
 13→  const [activeTab, setActiveTab] = useState<'edit' | 'preview'>('edit');
 14→  const [format, setFormat] = useState<'txt' | 'json'>('txt');
 15→  const [copied, setCopied] = useState(false);
 16→  const [data, setData] = useState<SourceOfTruthData>({
 17→    description: '',
 18→    type: 'SaaS B2B',
 19→    founded: new Date().getFullYear().toString(),
 20→    location: 'Paris, France',
 21→    services: [{ name: 'AEO Score Analysis', description: 'Analyse automatique de la qualité de votre contenu pour les systèmes IA.', category: 'Analytics' }],
 22→    faqs: [{ question: "Qu'est-ce que l'AEO ?", answer: "L'AEO est l'optimisation de contenu pour les moteurs de réponse IA." }]
 23→  });
 24→
 25→  useEffect(() => {
 26→    if (project) {
 27→      setData(prev => ({
 28→        ...prev,
 29→        description: `Plateforme d'optimisation pour les moteurs de réponse IA (AEO). Analyse et améliore la visibilité de ${project.name} auprès des assistants IA.`,
 30→      }));
 31→    }
 32→  }, [project]);
 33→
 34→  if (!isOpen || !project) return null;
 35→
 36→  const handleServiceChange = (idx: number, field: string, value: string) => {
 37→    const newServices = [...data.services];
 38→    (newServices[idx] as any)[field] = value;
 39→    setData({ ...data, services: newServices });
 40→  };
 41→
 42→  const handleFaqChange = (idx: number, field: string, value: string) => {
 43→    const newFaqs = [...data.faqs];
 44→    (newFaqs[idx] as any)[field] = value;
 45→    setData({ ...data, faqs: newFaqs });
 46→  };
 47→
 48→  const addService = () => setData({ ...data, services: [...data.services, { name: '', description: '', category: '' }] });
 49→  const removeService = (idx: number) => setData({ ...data, services: data.services.filter((_, i) => i !== idx) });
 50→
 51→  const addFaq = () => setData({ ...data, faqs: [...data.faqs, { question: '', answer: '' }] });
 52→  const removeFaq = (idx: number) => setData({ ...data, faqs: data.faqs.filter((_, i) => i !== idx) });
 53→
 54→  const generateContent = () => {
 55→    const projectInfo = { name: project.name, domain: project.domain };
 56→    return format === 'json' 
 57→      ? LLM_TRUTH_TEMPLATES.json(projectInfo, data)
 58→      : LLM_TRUTH_TEMPLATES.txt(projectInfo, data);
 59→  };
 60→
 61→  const handleCopy = () => {
 62→    navigator.clipboard.writeText(generateContent());
 63→    setCopied(true);
 64→    setTimeout(() => setCopied(false), 2000);
 65→  };
 66→
 67→  const handleDownload = () => {
 68→    const blob = new Blob([generateContent()], { type: format === 'json' ? 'application/json' : 'text/plain' });
 69→    const url = URL.createObjectURL(blob);
 70→    const a = document.createElement('a');
 71→    a.href = url;
 72→    a.download = `llm.${format}`;
 73→    document.body.appendChild(a);
 74→    a.click();
 75→    document.body.removeChild(a);
 76→    URL.revokeObjectURL(url);
 77→  };
 78→
 79→  return (
 80→    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
 81→      <div className="absolute inset-0 bg-black/80 backdrop-blur-sm" onClick={onClose}></div>
 82→      <div className="relative bg-[#0f1115] border border-white/[0.08] rounded-2xl w-full max-w-5xl h-[85vh] flex flex-col shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-200">
 83→        
 84→        {/* Header */}
 85→        <div className="p-6 border-b border-white/[0.08] flex items-center justify-between bg-white/[0.04]">
 86→          <div className="flex items-center gap-3">
 87→            <div className="w-10 h-10 rounded-2xl bg-purple-500/20 flex items-center justify-center text-purple-400 border border-purple-500/30">
 88→              <FileText size={20} />
 89→            </div>
 90→            <div>
 91→              <h3 className="text-lg font-sans font-bold text-white">LLM Source of Truth</h3>
 92→              <p className="text-xs text-gray-500">Générez le fichier de référence pour les IA (llm.txt / llm.json)</p>
 93→            </div>
 94→          </div>
 95→          <div className="flex items-center gap-2">
 96→            <div className="flex bg-black/40 rounded-full p-1 mr-4 border border-white/[0.08]">
 97→              <button onClick={() => setActiveTab('edit')} className={`px-4 py-1.5 rounded-md text-sm transition-all ${activeTab === 'edit' ? 'bg-white/[0.08] text-white' : 'text-gray-500 hover:text-gray-300'}`}>Éditer</button>
 98→              <button onClick={() => setActiveTab('preview')} className={`px-4 py-1.5 rounded-md text-sm transition-all ${activeTab === 'preview' ? 'bg-purple-500/20 text-purple-300' : 'text-gray-500 hover:text-gray-300'}`}>Aperçu</button>
 99→            </div>
100→            <button onClick={onClose} className="p-2 hover:bg-white/[0.08] rounded-full transition-colors text-gray-500 hover:text-white"><X size={20} /></button>
101→          </div>
102→        </div>
103→
104→        {/* Content */}
105→        <div className="flex-1 overflow-y-auto custom-scrollbar bg-[#000000]">
106→          {activeTab === 'edit' ? (
107→            <div className="p-8 max-w-4xl mx-auto space-y-8">
108→              
109→              {/* Identity Section */}
110→              <section className="space-y-4">
111→                <h4 className="text-sm font-bold text-purple-400 uppercase tracking-wider flex items-center gap-2">
112→                  <Building2 size={16} /> Identité Organisation
113→                </h4>
114→                <div className="grid grid-cols-2 gap-4">
115→                  <div className="col-span-2">
116→                    <label className="block text-xs text-gray-500 mb-1">Description courte (Context Window friendly)</label>
117→                    <textarea 
118→                      value={data.description}
119→                      onChange={(e) => setData({...data, description: e.target.value})}
120→                      className="w-full bg-black/40 border border-white/[0.08] rounded-xl p-3 text-white focus:border-purple-500/50 outline-none h-24 text-sm"
121→                      placeholder="Décrivez votre organisation en 2-3 phrases factuelles..."
122→                    />
123→                  </div>
124→                  <div>
125→                    <label className="block text-xs text-gray-500 mb-1">Type</label>
126→                    <input 
127→                      type="text" value={data.type}
128→                      onChange={(e) => setData({...data, type: e.target.value})}
129→                      className="w-full bg-black/40 border border-white/[0.08] rounded-xl p-3 text-white text-sm" 
130→                    />
131→                  </div>
132→                  <div>
133→                    <label className="block text-xs text-gray-500 mb-1">Année création</label>
134→                    <div className="relative">
135→                      <Calendar className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500" size={14} />
136→                      <input 
137→                        type="text" value={data.founded}
138→                        onChange={(e) => setData({...data, founded: e.target.value})}
139→                        className="w-full bg-black/40 border border-white/[0.08] rounded-xl p-3 pl-9 text-white text-sm" 
140→                      />
141→                    </div>
142→                  </div>
143→                  <div className="col-span-2">
144→                    <label className="block text-xs text-gray-500 mb-1">Localisation</label>
145→                    <div className="relative">
146→                      <MapPin className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500" size={14} />
147→                      <input 
148→                        type="text" value={data.location}
149→                        onChange={(e) => setData({...data, location: e.target.value})}
150→                        className="w-full bg-black/40 border border-white/[0.08] rounded-xl p-3 pl-9 text-white text-sm" 
151→                      />
152→                    </div>
153→                  </div>
154→                </div>
155→              </section>
156→
157→              {/* Services Section */}
158→              <section className="space-y-4 pt-6 border-t border-white/[0.06]">
159→                <div className="flex justify-between items-center">
160→                  <h4 className="text-sm font-bold text-purple-400 uppercase tracking-wider flex items-center gap-2">
161→                    <Sparkles size={16} /> Services & Offres
162→                  </h4>
163→                  <button onClick={addService} className="text-xs flex items-center gap-1 text-gray-500 hover:text-white"><Plus size={14} /> Ajouter</button>
164→                </div>
165→                {data.services.map((service, idx) => (
166→                  <div key={idx} className="bg-white/[0.04] p-4 rounded-2xl border border-white/[0.06] group relative">
167→                    <button onClick={() => removeService(idx)} className="absolute top-4 right-4 text-gray-600 hover:text-red-400 opacity-0 group-hover:opacity-100 transition-opacity"><Trash2 size={16} /></button>
168→                    <div className="grid grid-cols-2 gap-4 mb-3">
169→                      <input 
170→                        placeholder="Nom du service"
171→                        value={service.name}
172→                        onChange={(e) => handleServiceChange(idx, 'name', e.target.value)}
173→                        className="bg-black/40 border border-white/[0.08] rounded p-2 text-sm text-white"
174→                      />
175→                      <input 
176→                        placeholder="Catégorie"
177→                        value={service.category}
178→                        onChange={(e) => handleServiceChange(idx, 'category', e.target.value)}
179→                        className="bg-black/40 border border-white/[0.08] rounded p-2 text-sm text-white"
180→                      />
181→                    </div>
182→                    <textarea 
183→                      placeholder="Description factuelle..."
184→                      value={service.description}
185→                      onChange={(e) => handleServiceChange(idx, 'description', e.target.value)}
186→                      className="w-full bg-black/40 border border-white/[0.08] rounded p-2 text-sm text-white h-16"
187→                    />
188→                  </div>
189→                ))}
190→              </section>
191→
192→              {/* FAQ Section */}
193→              <section className="space-y-4 pt-6 border-t border-white/[0.06]">
194→                <div className="flex justify-between items-center">
195→                  <h4 className="text-sm font-bold text-purple-400 uppercase tracking-wider flex items-center gap-2">
196→                    <FileText size={16} /> FAQ (Knowledge Graph)
197→                  </h4>
198→                  <button onClick={addFaq} className="text-xs flex items-center gap-1 text-gray-500 hover:text-white"><Plus size={14} /> Ajouter</button>
199→                </div>
200→                {data.faqs.map((faq, idx) => (
201→                  <div key={idx} className="bg-white/[0.04] p-4 rounded-2xl border border-white/[0.06] group relative">
202→                    <button onClick={() => removeFaq(idx)} className="absolute top-4 right-4 text-gray-600 hover:text-red-400 opacity-0 group-hover:opacity-100 transition-opacity"><Trash2 size={16} /></button>
203→                    <input 
204→                      placeholder="Question ?"
205→                      value={faq.question}
206→                      onChange={(e) => handleFaqChange(idx, 'question', e.target.value)}
207→                      className="w-full bg-black/40 border border-white/[0.08] rounded p-2 text-sm text-white mb-2 font-medium"
208→                    />
209→                    <textarea 
210→                      placeholder="Réponse..."
211→                      value={faq.answer}
212→                      onChange={(e) => handleFaqChange(idx, 'answer', e.target.value)}
213→                      className="w-full bg-black/40 border border-white/[0.08] rounded p-2 text-sm text-gray-300 h-16"
214→                    />
215→                  </div>
216→                ))}
217→              </section>
218→
219→            </div>
220→          ) : (
221→            <div className="h-full flex flex-col">
222→              <div className="p-4 border-b border-white/[0.08] flex items-center justify-between bg-[#111111]">
223→                <div className="flex items-center gap-4">
224→                  <button onClick={() => setFormat('txt')} className={`text-xs font-bold px-3 py-1 rounded transition-colors ${format === 'txt' ? 'bg-purple-500 text-white' : 'text-gray-500 hover:text-white'}`}>llm.txt</button>
225→                  <button onClick={() => setFormat('json')} className={`text-xs font-bold px-3 py-1 rounded transition-colors ${format === 'json' ? 'bg-purple-500 text-white' : 'text-gray-500 hover:text-white'}`}>llm.json</button>
226→                </div>
227→                <div className="flex gap-2">
228→                  <button onClick={handleCopy} className="flex items-center gap-2 px-3 py-1.5 bg-white/[0.04] hover:bg-purple-500/10 rounded text-xs font-medium text-white border border-white/[0.08]">
229→                    {copied ? <Check size={14} className="text-purple-300" /> : <Copy size={14} />}
230→                    {copied ? 'Copié' : 'Copier'}
231→                  </button>
232→                  <button onClick={handleDownload} className="flex items-center gap-2 px-3 py-1.5 bg-gradient-to-r from-purple-500 to-violet-600 text-white hover:from-purple-400 hover:to-violet-500 rounded text-xs font-bold">
233→                    <Download size={14} /> Télécharger
234→                  </button>
235→                </div>
236→              </div>
237→              <div className="flex-1 bg-[#111111] p-6 overflow-auto">
238→                <pre className="font-mono text-sm text-gray-300 whitespace-pre-wrap">{generateContent()}</pre>
239→              </div>
240→            </div>
241→          )}
242→        </div>
