109→    message,
110→  )}`;
111→
112→  return (
113→    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/70 p-4">
114→      <div className="h-full w-full overflow-hidden rounded-2xl border border-leadradar-border bg-[#0B0F1A] md:h-auto md:max-h-[90vh] md:max-w-4xl">
